<script>
    // -- Story Mode Data & Functions --
   const storySteps = [
      {
        message: "👋 <b>Hi!</b> Let's explore pareto frontiers together! 📈",
        glow: [], duration: 4000
      },
      {
        message: "<b>Pareto frontiers</b> are curves made up of optimal trade-off points where improving one goal means sacrificing another.",
        glow: [], duration: 6000
      },
      {
        message: "This interactive plot shows how different configurations balance AI factory efficiency in generating tokens at scale against the speed of token generation experienced by individual users.",
        glow: [], duration: 7000
      },
      {
        message: "🔍 Let's explore a couple of points, starting with <b>Hopper</b>.",
        glow: [], duration: 4000
      },
      {
        message: "<b>Hopper</b> introduced <b>FP8 inference</b> and <b>NVL8</b>, unlocking leading performance!",
        glow: [], duration: 5000
      },
      {
        message: "👉 Click the glowing <b>Hopper</b> data point to see <b>32 tokens/sec</b> user throughput.",
        glow: ["HPR‑250"], highlight: "HPR‑250", duration: 8000
      },
      {
        message: "At the AI factory scale 🏭, that same <b>Hopper</b> config delivers <b>98,000 tokens/sec per MW</b>! 🔋",
        glow: ["HPR‑250"], highlight: "HPR‑250", duration: 6000
      },
      {
        message: "The dotted rectangle represents the potential <b>factory productivity</b> – balancing scale and user experience.",
        glow: ["HPR‑250"], highlight: "HPR‑250", duration: 6000
      },
      {
        message: "Notice how the <b>Blackwell Ultra</b> curve shifts out to the right—unlocking a new frontier of factory productivity!",
        glow: [], duration: 6000
      },
      {
        message: "👉 Click the glowing <b>Blackwell</b> data point to see lightning‑fast user experience—<b>10× faster</b> than Hopper! ⚡️",
        glow: ["BCL‑350"], highlight: "BCL‑350", duration: 8000
      },
      {
        message: "At factory level, we’re delivering <b>over 450,000 tokens/sec per MW</b> — <b>5× more throughput </b> than Hopper! 💪",
        glow: ["BCL‑350"], highlight: "BCL‑350", duration: 6000
      },
      {
        message: "Some key innovations enabling this generational leap are <b>NVLink</b>,  <b>NVFP4</b>,  and <b>NVIDIA Dynamo!</b>",
        glow: ["BCL‑350"], highlight: "BCL‑350", duration: 6000
      },
      {
        message: "In NVL72 rack-scale systems, the NVLink spine connects <b>72 GPUs</b> at <b>130 TB/s</b> of bandwidth - creating a coherent domain that communicates like one giant GPU!!",
        glow: ["BCL‑350"], highlight: "BCL‑350", duration: 7000
      },
      {
        message: "NVFP4 enables up to <b>3× greater throughput </b> over FP8 while retaining accuracy! 🎯",
        glow: ["BCL‑350"], highlight: "BCL‑350", duration: 5000
      },
      {
        message: " And <b>NVIDIA Dynamo</b>  enables critical open-source distributed inference optimizations.",
        glow: ["BCL‑350"], highlight: "BCL‑350", duration: 5000
      },
      {
        message: "All of this yields <b>50× better AI factory productivity</b> vs. Hopper—driving greater profits and innovation! 🚀",
        glow: ["BCL‑350"], highlight: "BCL‑350", duration: 6000
      },
      {
        message: "To <b>THINK SMART</b> 💡 about inference, we need to understand the trade-offs of different configurations and how they impact data center efficiency and user experience. Continue playing with the different points on the pareto frontier to further explore this concept!",
        glow: [], duration: 12000
      }
    ];
    let storyIndex = 0;

     function showStoryStep() {
      if (storyIndex >= storySteps.length) {
        document.getElementById('toy-head').style.display = 'none';
        document.getElementById('speech-bubble').style.display = 'none';
        g.selectAll('circle')
         .attr('stroke-width',1)
         .attr('filter', null);
        return;
      }
      const step = storySteps[storyIndex];
      const bubble = document.getElementById('speech-bubble');
      bubble.innerHTML = step.message;  // allow HTML tags

      // reset all circles
      svg.selectAll('circle')
         .attr('stroke-width',1)
         .attr('filter', null);

      // highlight stroke if specified
      if (step.highlight) {
        svg.selectAll('circle')
           .filter(d => d.config === step.highlight)
           .attr('stroke', '#fff')
           .attr('stroke-width', 4);
      }

      // dramatic neon glow
      if (step.glow.length) {
        g.selectAll('circle')
         .filter(d => step.glow.includes(d.config))
         .attr('filter', d => 
           d.gpu === 'Blackwell'
             ? 'url(#green-glow)'
             : 'url(#hopper-glow)'
         );
      }

      storyIndex++;
      setTimeout(showStoryStep, step.duration);
    }

    document.getElementById('start-story').addEventListener('click', () => {
      storyIndex = 0;
      document.getElementById('toy-head').style.display = 'block';
      document.getElementById('speech-bubble').style.display = 'block';
      showStoryStep();
    });

    // -- Chart Code (with glow filter) --
    const data = [
  { gpu: 'Hopper',     tps_user: 7,   tps_mw: 179809, config: 'HPR‑010', showLines: false },
  { gpu: 'Hopper',     tps_user: 17,  tps_mw: 134073, config: 'HPR‑100', showLines: false },
  { gpu: 'Hopper',     tps_user: 32,  tps_mw: 98604,  config: 'HPR‑250', showLines: true },
  { gpu: 'Hopper',     tps_user: 56,  tps_mw: 65001,  config: 'HPR‑300', showLines: false },
  { gpu: 'Hopper',     tps_user: 92,  tps_mw: 16465,  config: 'HPR‑600', showLines: false },
  { gpu: 'Hopper',     tps_user: 128, tps_mw: 8998,   config: 'HPR‑700', showLines: false },
  { gpu: 'Hopper',     tps_user: 164, tps_mw: 6198,   config: 'HPR‑800', showLines: false },

  { gpu: 'Blackwell',  tps_user: 34,  tps_mw: 1000261, config: 'BCL‑025', showLines: false },
  { gpu: 'Blackwell',  tps_user: 99,  tps_mw: 798648,  config: 'BCL‑200', showLines: false },
  { gpu: 'Blackwell',  tps_user: 166, tps_mw: 722110,  config: 'BCL‑250', showLines: false },
  { gpu: 'Blackwell',  tps_user: 248, tps_mw: 595169,  config: 'BCL‑300', showLines: false  },
  { gpu: 'Blackwell',  tps_user: 345, tps_mw: 451426,  config: 'BCL‑350', showLines: true },
  { gpu: 'Blackwell',  tps_user: 411, tps_mw: 297416,  config: 'BCL‑400', showLines: false },
  { gpu: 'Blackwell',  tps_user: 453, tps_mw: 174208,  config: 'BCL‑450', showLines: false },
  { gpu: 'Blackwell',  tps_user: 478, tps_mw: 51934,   config: 'BCL‑475', showLines: false },
  { gpu: 'Blackwell',  tps_user: 617, tps_mw: 19265,   config: 'BCL‑525', showLines: false }
];

    let chatTimer = null;
    const margin = { top: 100, right: 20, bottom: 100, left: 110 };
    const chartDiv = document.getElementById('chart');
    const width  = chartDiv.clientWidth  - margin.left - margin.right;
    const height = chartDiv.clientHeight - margin.top  - margin.bottom;

    const svg = d3.select('#chart').append('svg')
      .attr('width',  width + margin.left + margin.right)
      .attr('height', height + margin.top  + margin.bottom);

   // neon-glow filters
    const defs = svg.append('defs');
    // green glow
    const greenFilter = defs.append('filter')
      .attr('id','green-glow')
      .attr('x','-400%').attr('y','-400%')
      .attr('width','1200%').attr('height','1200%');
    greenFilter.append('feGaussianBlur')
      .attr('in','SourceGraphic').attr('stdDeviation','20').attr('result','blur');
    greenFilter.append('feFlood')
      .attr('flood-color','#76B900')
      .attr('result','color')
      .attr('flood-opacity','1');
    greenFilter.append('feComposite')
      .attr('in','color').attr('in2','blur').attr('operator','in').attr('result','coloredBlur');
    const greenMerge = greenFilter.append('feMerge');
    greenMerge.append('feMergeNode').attr('in','blur');
    greenMerge.append('feMergeNode').attr('in','blur');
    greenMerge.append('feMergeNode').attr('in','blur');
    greenMerge.append('feMergeNode').attr('in','blur');
    greenMerge.append('feMergeNode').attr('in','SourceGraphic');

    // grey glow
    const greyFilter = defs.append('filter')
      .attr('id','hopper-glow')
      .attr('x','-1600%').attr('y','-1600%')
      .attr('width','2400%').attr('height','2400%');
    greyFilter.append('feGaussianBlur')
      .attr('in','SourceGraphic')
      .attr('stdDeviation','20')
      .attr('result','blur');
    greyFilter.append('feFlood')
      .attr('flood-color','#ccc')
      .attr('flood-opacity','1')
      .attr('result','color');
    greyFilter.append('feComposite')
      .attr('in','color').attr('in2','blur').attr('operator','in').attr('result','coloredBlur');
    const greyMerge = greyFilter.append('feMerge');
    greyMerge.append('feMergeNode').attr('in','blur');
    greyMerge.append('feMergeNode').attr('in','blur');
    greyMerge.append('feMergeNode').attr('in','blur');
    greyMerge.append('feMergeNode').attr('in','blur');
    greyMerge.append('feMergeNode').attr('in','SourceGraphic');

    const g = svg.append('g')
      .attr('transform', `translate(${margin.left},${margin.top})`);

    // Chart title
    g.append('text')
      .attr('x', width/2).attr('y', -margin.top/2)
      .attr('text-anchor', 'middle')
      .attr('fill', '#e0e0e0')
      .attr('class', 'chart-title')
      .attr('font-weight', 'bold')
      .text('NVIDIA Blackwell Ultra AI Factory Output');
    
    // Scales
    const x = d3.scaleLinear()
      .domain([0, d3.max(data, d => d.tps_user)*1.1])
      .range([0, width]);
    const y = d3.scaleLinear()
      .domain([0, d3.max(data, d => d.tps_mw)*1.1])
      .range([height, 0]);

    // X axis
    const xAxis = g.append('g')
      .attr('transform', `translate(0,${height})`)
      .call(d3.axisBottom(x).ticks(5).tickSize(-height).tickPadding(10));
    xAxis.selectAll('line').attr('stroke', '#444');
    xAxis.selectAll('text').attr('font-size','12px');
    g.append('text')
      .attr('class','axis-label')
      .attr('x', width*2/7-70).attr('y', height+60)
      .text('Tokens per Second for One User (Responsiveness)');

    // Y axis
    const yAxis = g.append('g')
      .call(d3.axisLeft(y).ticks(5).tickSize(-width).tickPadding(10));
    yAxis.selectAll('line').attr('stroke', '#444');
    yAxis.selectAll('text').attr('font-size','12px');
    g.append('text')
      .attr('class','axis-label')
      .attr('transform','rotate(-90)')
      .attr('x', -height+50).attr('y', -80)
      .text('Tokens per Second in 1 MW (Throughput)');

    // Performance curves
    const lineGen = d3.line().curve(d3.curveMonotoneX)
      .x(d => x(d.tps_user)).y(d => y(d.tps_mw));
    ['Blackwell','Hopper'].forEach(type => {
      const series = data.filter(d => d.gpu===type)
                         .sort((a,b)=>a.tps_user - b.tps_user);
      g.append('path').datum(series)
        .attr('fill','none')
        .attr('stroke', type==='Blackwell' ? '#76B900' : '#ccc')
        .attr('opacity', 0)
        .attr('d', lineGen)
        .transition().duration(1200).attr('opacity',1);
    });

    // Points
    g.selectAll('.point').data(data).enter().append('circle')
      .attr('class', d=>`point ${d.gpu.toLowerCase()}`)
      .attr('cx', d=>x(d.tps_user))
      .attr('cy', d=>y(d.tps_mw))
      .attr('r',7)
      .on('mouseover', (e,d)=>d3.select('#tooltip')
        .style('opacity',1)
        .html(`<strong>${d.config}</strong>`)
        .style('left',`${e.pageX+10}px`)
        .style('top',`${e.pageY-28}px`))
      .on('mouseout', ()=>d3.select('#tooltip').style('opacity',0))
      .on('click', onClick);

    // Dotted lines + labels
    const dottedLayer = g.append('g').attr('class','dotted-layer');
    function updateDottedLines(){
      dottedLayer.selectAll('*').remove();
      data.filter(d=>d.showLines).forEach(d=>{
        dottedLayer.append('line')
          .attr('class','dotted-line')
          .attr('x1', x(0)).attr('y1', y(d.tps_mw))
          .attr('x2', x(d.tps_user)).attr('y2', y(d.tps_mw));
        dottedLayer.append('line')
          .attr('class','dotted-line')
          .attr('x1', x(d.tps_user)).attr('y1', y(0))
          .attr('x2', x(d.tps_user)).attr('y2', y(d.tps_mw));
        const color = d.gpu==='Blackwell' ? '#76B900' : '#ccc';
        const text = d.gpu==='Blackwell'
          ? 'GB300 NVL72 NVFP4 Dynamo'
          : 'Hopper FP8 NVL8';
        dottedLayer.append('text')
          .attr('x', x(d.tps_user)+8)
          .attr('y', y(d.tps_mw)-8)
          .text(text)
          .attr('fill', color)
          .attr('font-weight','bold')
         
           .attr('class','graph-label')
          .attr('pointer-events','none');
      });
    }
    updateDottedLines();

    function onClick(event,d){
      if(chatTimer) clearInterval(chatTimer);
      g.selectAll('circle').attr('stroke-width',1).attr('filter',null);
      d3.select(event.currentTarget).attr('stroke','#fff').attr('stroke-width',3);
      d3.select('#gpu').text(d.gpu);
      d3.select('#tps_user').text(d.tps_user.toFixed(0));
      d3.select('#users_supported').text(Math.floor(d.tps_mw/d.tps_user).toLocaleString());
      d3.select('#tps_factory').text(d.tps_mw.toLocaleString());
      simulateChat(d.tps_user);
    }

    function simulateChat(tps_user){
      const chat = d3.select('#chat-messages');
      chat.html('');
      const sample = `A large language model (LLM) works a bit like a very advanced text prediction system that can understand context and relationships between words. Instead of reading one word at a time in order, it looks at all the words in a sentence or paragraph at once, figuring out which ones are most important to focus on. It does this using a system called “attention,” which lets the model decide how much each word influences the meaning of the others. To keep track of word order, it also uses a kind of numbering system so it knows which words came first, second, and so on. These steps are repeated through many layers, each improving the model’s understanding, until it builds a deep sense of context. After being trained on huge amounts of text, the model learns patterns in language, which it uses to generate new sentences, answer questions, or hold a conversation in a way that feels surprisingly human`.split(/\s+/);

      let idx=0, interval=1000/tps_user;
      chatTimer = setInterval(()=>{
        if(idx<sample.length){
          chat.append('span').text(sample[idx++]+' ');
          chat.node().scrollTop = chat.node().scrollHeight;
        } else clearInterval(chatTimer);
      }, interval);
    }
  </script></div>	

